Since you now have languageInfo in the tree, you could switch this function up a bit and trim out the highlighted language action.

```js
const mapStateToProps = state => {
  const currentKernel = objectPath.get(state, [
    'entities',
    'serversById',
    state.ui.currentServerId,
    'server',
    'activeKernelsByName',
    state.ui.currentKernelName,
    'kernel',
  ]);

  const highlightedLanguage = objectPath.get(currentKernel, [
    'languageInfo',
    'name',
  ]);

  return {
    repo: state.ui.repo,
    gitref: state.ui.gitref,
    source: state.ui.source,
    platform: state.ui.platform,
    showPanel: state.ui.showPanel,
    currentServerId: state.ui.currentServerId,
    currentKernelName: state.ui.currentKernelName,
    highlightedLanguage,
    currentKernel,
    currentServer: objectPath.get(state, [
      'entities',
      'serversById',
      state.ui.currentServerId,
      'server',
    ]),
  };
};
```

